def patch_file(path: str, old_str: str, new_str: str) -> str:
    try:
        full = _safe_path(path)
        with open(full, "r") as f:
            content = f.read()
        count = content.count(old_str)
        if count == 0:
            return "[error] old_str tidak ditemukan persis di file. Cek ulang spasi/indentasi."
        if count > 1:
            return f"[error] old_str muncul {count} kali, harus unik. Perjelas konteks (tambah baris sekitar)."
        new_content = content.replace(old_str, new_str)
        with open(full, "w") as f:
            f.write(new_content)
        return f"[ok] file dipatch: {path}"
    except Exception as e:
        return f"[error] {e}"


def read_file(path: str, start_line: int = None, num_lines: int = None) -> str:
    try:
        full = _safe_path(path)
        with open(full, "r") as f:
            content = f.read()
        lines = content.split("\n")
        total_lines = len(lines)

        if start_line is not None:
            start_idx = max(0, int(start_line) - 1)
            n = int(num_lines) if num_lines else DEFAULT_CHUNK_LINES
            selected = lines[start_idx:start_idx + n]
            end_line = start_idx + len(selected)
            header = f"[baris {start_idx + 1}-{end_line} dari {total_lines} total baris]\n"
            return header + "\n".join(selected)

        if len(content) > READ_FILE_LIMIT:
            truncated = content[:READ_FILE_LIMIT]
            sisa = len(content) - READ_FILE_LIMIT
            return (
                f"{truncated}\n\n[...dipotong, {sisa} karakter lagi ({total_lines} baris total). "
                f"Pakai start_line+num_lines buat baca bagian tertentu...]"
            )
        return content
    except Exception as e:
        return f"[error] {e}"


